// ============================================================
// RENEWAL ALERT SYSTEM — Deal Fetcher & Filter Engine
// Fetches open deals → filters by service type & renewal date
// within next 30 days → groups by owner → routes to dispatchers
//
// Notification targets: deal ASSIGNED_BY_ID + last observer
// No department filter — any deal owner is a valid target
// ============================================================

const MAIN_WEBHOOK  = 'https://intranet.rajlaxmiworld.com/rest/316/du14lqdt4ijmvzx4';
const BITRIX_DOMAIN = 'https://intranet.rajlaxmiworld.com';
const BREVO_API_KEY = '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';
const FROM_EMAIL    = 'info@averlonworld.com';
const FROM_NAME     = 'Averlon CRM';
const HOD_USER_ID   = '316';
const HOD_NAME      = 'Dr. Aarti Arya';
const HOD_EMAIL     = 'dr.aartiarya@rajlaxmiworld.com';
const MAX_DEALS_PER_MSG   = 8;
const RENEWAL_WINDOW_DAYS = 30;

const SERVICE_GROUPS = {};
//const SELECTED_EMPLOYEES = [];

//const SELECTED_EMPLOYEES = [{id:'71603', name:'Mohd Awaish', email:'awaish@rajlaxmiworld.com'}];
const SELECTED_EMPLOYEES = [];



// ── IST time setup ────────────────────────────────────────
const IST_OFFSET_MS = 5.5 * 60 * 60 * 1000;
const now           = new Date();
const nowIST        = new Date(now.getTime() + IST_OFFSET_MS);
const todayStr      = nowIST.toISOString().slice(0, 10);
const istHour       = nowIST.getUTCHours();
const istMinute     = nowIST.getUTCMinutes();

// ── Trigger slot detection ────────────────────────────────
const isReminder1  = (istHour === 10 && istMinute >= 0 && istMinute < 59);
const isReminder2  = (istHour === 13 && istMinute >= 0 && istMinute < 55);
const isReminder3  = (istHour === 17 && istMinute >= 0 && istMinute < 55);
const isEscalation = (istHour === 18 && istMinute >= 0 && istMinute < 59);
const isAnySlot    = isReminder1 || isReminder2 || isReminder3 || isEscalation;
const isReminder   = isReminder1 || isReminder2 || isReminder3;

const route       = isEscalation ? 'ESCALATION' : isReminder ? 'REMINDER' : 'NONE';
const triggerSlot = isReminder1 ? '10:30am' : isReminder2 ? '1pm' : isReminder3 ? '5pm' : isEscalation ? '6:30pm' : 'unknown';

console.log(`\n${'═'.repeat(60)}`);
console.log(`🔄 RENEWAL ALERT SYSTEM | IST: ${istHour}:${String(istMinute).padStart(2, '0')} | Slot: ${triggerSlot}`);
console.log('═'.repeat(60));

if (!isAnySlot) {
  console.log(`⏱ Not a scheduled slot — skipping.`);
  return [{ json: { hasDeals: false, message: `Not a scheduled slot (${istHour}:${String(istMinute).padStart(2, '0')} IST)`, runDate: todayStr } }];
}

// ────────────────────────────────────────────────────────────
// UTILITY FUNCTIONS
// ────────────────────────────────────────────────────────────

function parseDate(str) {
  if (!str) return null;
  const [y, m, d] = str.split('-').map(Number);
  if (!y || !m || !d) return null;
  return new Date(y, m - 1, d);
}

function parseBitrixDate(dateStr) {
  if (!dateStr) return null;
  const part = new Date(dateStr).toLocaleDateString('en-CA', { timeZone: 'Asia/Kolkata' });
  return parseDate(part);
}

function daysUntil(dateStr) {
  const d = parseBitrixDate(dateStr);
  if (!d) return null;
  return Math.floor((d - parseDate(todayStr)) / 86400000);
}

function formatDate(dateStr) {
  const d = parseBitrixDate(dateStr);
  if (!d) return '—';
  return d.toLocaleDateString('en-IN', { day: '2-digit', month: 'short', year: 'numeric' });
}

function filterByService(deal) {
  const title = (deal.TITLE || '').toLowerCase();
  return Object.values(SERVICE_GROUPS).some(group =>
    group.some(keyword => title.includes(keyword))
  );
}

function groupByOwner(deals) {
  const groups = {};
  for (const deal of deals) {
    const ownerId = String(deal.ASSIGNED_BY_ID || 'unassigned');
    if (!groups[ownerId]) groups[ownerId] = [];
    groups[ownerId].push(deal);
  }
  return groups;
}

function dealUrl(id) {
  return `${BITRIX_DOMAIN}/crm/deal/details/${id}/`;
}

function extractEmail(u) {
  if (Array.isArray(u.EMAIL))      return u.EMAIL[0]?.VALUE || '';
  if (typeof u.EMAIL === 'string') return u.EMAIL;
  return '';
}

function buildUserRecord(u) {
  return {
    id:    String(u.ID),
    name:  `${u.NAME || ''} ${u.LAST_NAME || ''}`.trim() || `User #${u.ID}`,
    email: extractEmail(u).trim()
  };
}

// ── Parallel fetch helper with concurrency cap ────────────
// Runs up to `concurrency` promises at once instead of one-at-a-time.
async function parallelMap(items, asyncFn, concurrency = 20) {
  const results = new Array(items.length);
  let index = 0;

  async function worker() {
    while (index < items.length) {
      const i = index++;
      results[i] = await asyncFn(items[i], i);
    }
  }

  const workers = Array.from({ length: Math.min(concurrency, items.length) }, worker);
  await Promise.all(workers);
  return results;
}

// ────────────────────────────────────────────────────────────
// STEP 1 — Fetch ALL active users → allUserMap
//   Resolves name + email for any user ID (owner or observer)
//   No department filtering — all users are loaded
// ────────────────────────────────────────────────────────────
console.log(`\n📡 STEP 1 — Fetching all active users`);

let allUsersRaw = [];
try {
  const firstRes = await this.helpers.request({
    method: 'GET',
    url: `${MAIN_WEBHOOK}/user.get.json?filter[ACTIVE]=true&start=0`,
    json: true
  });
  allUsersRaw = firstRes.result || [];

  if (firstRes.total && firstRes.total > 50) {
    const totalPages = Math.ceil(firstRes.total / 50);
    const pageStarts = Array.from({ length: totalPages - 1 }, (_, i) => (i + 1) * 50);

    const pageResults = await parallelMap(pageStarts, async (start) => {
      const res = await this.helpers.request({
        method: 'GET',
        url: `${MAIN_WEBHOOK}/user.get.json?filter[ACTIVE]=true&start=${start}`,
        json: true
      });
      return res.result || [];
    }, 10);

    for (const batch of pageResults) allUsersRaw = allUsersRaw.concat(batch);
  }
} catch (e) {
  throw new Error(`[MAIN] User fetch failed: ${e.message}`);
}

const allUserMap = {};
for (const u of allUsersRaw) {
  allUserMap[String(u.ID)] = buildUserRecord(u);
}
console.log(`   ✅ ${allUsersRaw.length} active users loaded`);

const selectedIds  = new Set(SELECTED_EMPLOYEES.map(e => String(e.id)));
const hasSelection = selectedIds.size > 0;
if (hasSelection) {
  console.log(`   🎯 Notification restricted to owner IDs: [${[...selectedIds].join(', ')}]`);
} else {
  console.log(`   🎯 No restriction — all deal owners will be notified`);
}

// ────────────────────────────────────────────────────────────
// STEP 2 — Fetch ALL open deals (with UF_CRM_RENEWAL_DATE)
// ────────────────────────────────────────────────────────────
console.log(`\n📡 STEP 2 — Fetching open deals`);

let allDeals = [];
try {
  const firstRes = await this.helpers.request({
    method: 'GET',
    url: `${MAIN_WEBHOOK}/crm.deal.list.json?filter[CLOSED]=N` +
         `&select[]=ID&select[]=TITLE&select[]=ASSIGNED_BY_ID` +
         `&select[]=CLOSEDATE&select[]=UF_CRM_RENEWAL_DATE&start=0`,
    json: true
  });
  allDeals = firstRes.result || [];

  if (firstRes.total && firstRes.total > 50) {
    const totalPages = Math.ceil(firstRes.total / 50);
    const pageStarts = Array.from({ length: totalPages - 1 }, (_, i) => (i + 1) * 50);

    const pageResults = await parallelMap(pageStarts, async (start) => {
      const res = await this.helpers.request({
        method: 'GET',
        url: `${MAIN_WEBHOOK}/crm.deal.list.json?filter[CLOSED]=N` +
             `&select[]=ID&select[]=TITLE&select[]=ASSIGNED_BY_ID` +
             `&select[]=CLOSEDATE&select[]=UF_CRM_RENEWAL_DATE&start=${start}`,
        json: true
      });
      return res.result || [];
    }, 10);

    for (const batch of pageResults) allDeals = allDeals.concat(batch);
  }
} catch (e) {
  throw new Error(`[MAIN] Deal fetch failed: ${e.message}`);
}
console.log(`   ✅ ${allDeals.length} open deals fetched`);

// ────────────────────────────────────────────────────────────
// STEP 3 — Filter by service type (TITLE match)
// ────────────────────────────────────────────────────────────
console.log(`\n🔍 STEP 3 — Filtering by service groups`);

const serviceDeals = allDeals;

// ── Fetch activities for ALL serviceDeals in parallel ─────
// No pre-filter applied — activity deadline takes priority over
// deal date fields, so a deal with a far CLOSEDATE may still
// qualify via a near activity deadline. We must fetch all.
console.log(`\n📡 Fetching activities for ${serviceDeals.length} deals (parallel, concurrency=20)`);

const activityMap = {};
await parallelMap(serviceDeals, async (deal) => {
  try {
    const res = await this.helpers.request({
      method: 'GET',
      url: `${MAIN_WEBHOOK}/crm.activity.list.json` +
           `?filter[OWNER_TYPE_ID]=2&filter[OWNER_ID]=${deal.ID}` +
           `&select[]=ID&select[]=RESPONSIBLE_ID&select[]=CREATED&select[]=DEADLINE` +
           `&order[CREATED]=DESC&start=0`,
      json: true
    });
    const activities = res.result || [];
    if (activities.length > 0) {
      activityMap[String(deal.ID)] = {
        observerId: String(activities[0].RESPONSIBLE_ID),
        deadline:   activities[0].DEADLINE
      };
    }
  } catch (e) {
    console.log(`   ⚠️ Activity fetch skipped for deal ${deal.ID}: ${e.message}`);
  }
}, 20);

console.log(`   ✅ ${serviceDeals.length} deals match target services`);

// ────────────────────────────────────────────────────────────
// STEP 4 — Filter by renewal date (0 to +30 days)
//   UF_CRM_RENEWAL_DATE takes priority; falls back to CLOSEDATE
// ────────────────────────────────────────────────────────────
console.log(`\n📅 STEP 4 — Filtering renewal dates (next ${RENEWAL_WINDOW_DAYS} days)`);

const renewalDeals = [];
let skippedNoDate = 0, skippedOutOfWindow = 0;

for (const deal of serviceDeals) {
  const activity   = activityMap[String(deal.ID)];
  const renewalRaw = activity?.deadline || deal.UF_CRM_RENEWAL_DATE || deal.CLOSEDATE;

  if (!renewalRaw) { skippedNoDate++; continue; }

  const days = daysUntil(renewalRaw);
  if (days === null || days < -RENEWAL_WINDOW_DAYS || days > RENEWAL_WINDOW_DAYS) { skippedOutOfWindow++; continue; }

  renewalDeals.push({
    ...deal,
    _renewalDateRaw:       renewalRaw,
    _renewalDateFormatted: formatDate(renewalRaw),
    _daysLeft:             days,
    _renewalStatus:        'UPCOMING_30_DAYS',
    _dealUrl:              dealUrl(deal.ID)
  });
}

renewalDeals.sort((a, b) => a._daysLeft - b._daysLeft);

console.log(`   ✅ ${renewalDeals.length} deals renewing within ${RENEWAL_WINDOW_DAYS} days`);
console.log(`   ⬜ Skipped (no date)      : ${skippedNoDate}`);
console.log(`   ⬜ Skipped (out of window): ${skippedOutOfWindow}`);

if (renewalDeals.length === 0) {
  return [{
    json: {
      hasDeals: false,
      message:  `No renewal deals in next ${RENEWAL_WINDOW_DAYS} days`,
      isReminder, isEscalation, route, triggerSlot, runDate: todayStr
    }
  }];
}

// ────────────────────────────────────────────────────────────
// STEP 5 — Resolve last activity observer per deal
// ────────────────────────────────────────────────────────────
console.log(`\n📡 STEP 5 — Resolving last observer per deal`);
console.log(`   ✅ Observer resolved for ${Object.keys(activityMap).length} deal(s)`);

// ────────────────────────────────────────────────────────────
// STEP 6 — Group by owner & build output items
// ────────────────────────────────────────────────────────────
console.log(`\n📊 STEP 6 — Grouping by deal owner`);

const ownerGroups = groupByOwner(renewalDeals);
const output = [];

for (const [ownerId, deals] of Object.entries(ownerGroups)) {

  if (hasSelection && !selectedIds.has(ownerId)) {
    console.log(`   ⏭ Skipping owner ${ownerId} (not in SELECTED_EMPLOYEES)`);
    continue;
  }

  const owner = allUserMap[ownerId] || { id: ownerId, name: `User #${ownerId}`, email: '' };

  const observerIds = [...new Set(
    deals
      .map(d => activityMap[String(d.ID)]?.observerId)
      .filter(id => id && id !== ownerId)
  )];

  const observers = observerIds.map(id =>
    allUserMap[id] || { id, name: `User #${id}`, email: '' }
  );

  const notifyTargets = [owner, ...observers].filter((t, i, arr) =>
    arr.findIndex(x => x.id === t.id) === i
  );

  const dealItems = deals.map(d => {
    const obsId   = activityMap[String(d.ID)]?.observerId || null;
    const obsName = obsId ? (allUserMap[obsId]?.name || `User #${obsId}`) : null;
    return {
      id:                   String(d.ID),
      title:                d.TITLE || `Deal #${d.ID}`,
      renewalDate:          d._renewalDateRaw,
      renewalDateFormatted: d._renewalDateFormatted,
      daysLeft:             d._daysLeft,
      renewalStatus:        d._renewalStatus,
      assignedById:         String(d.ASSIGNED_BY_ID),
      assignedByName:       owner.name,
      assignedByEmail:      owner.email,
      observerId:           obsId,
      observerName:         obsName,
      url:                  d._dealUrl
    };
  });

  console.log(`   👤 ${owner.name} (${ownerId}) — ${owner.email || 'no email'} | ${dealItems.length} deal(s) | observers: [${observerIds.join(', ') || 'none'}]`);

  output.push({
    json: {
      employee:       owner,
      notifyTargets,
      deals:          dealItems,
      totalDeals:     dealItems.length,
      hasDeals:       true,
      triggerSlot,
      isReminder,
      isEscalation,
      route,
      mainWebhook:    MAIN_WEBHOOK,
      brevoApiKey:    BREVO_API_KEY,
      fromEmail:      FROM_EMAIL,
      fromName:       FROM_NAME,
      hodUserId:      HOD_USER_ID,
      hodName:        HOD_NAME,
      hodEmail:       HOD_EMAIL,
      bitrixDomain:   BITRIX_DOMAIN,
      maxDealsPerMsg: MAX_DEALS_PER_MSG,
      runDate:        todayStr
    }
  });
}

console.log(`\n${'═'.repeat(60)}`);
console.log(`✅ DONE: ${renewalDeals.length} renewal deal(s) → ${output.length} owner notification(s)`);
console.log('═'.repeat(60));

if (output.length === 0) {
  return [{
    json: {
      hasDeals: false,
      message:  `No notifiable owners found for renewal deals`,
      isReminder, isEscalation, route, triggerSlot, runDate: todayStr
    }
  }];
}

return output;
